class ExpiringCache:
    def __init__(self):
        self._cache = {}
        self._lock = RLock()

    def set(self, key, value, ttl):
        """Set a value in the cache with a time-to-live (ttl) in seconds."""
        expiration_time = time.time() + ttl
        with self._lock:
            self._cache[key] = (value, expiration_time)

    def get(self, key):
        """Retrieve a value from the cache. Returns None if the key is not found or expired."""
        with self._lock:
            self.cleanup()
            entry = self._cache.get(key)
            if entry:
                value, expiration_time = entry
                if time.time() < expiration_time:
                    return value
                else:
                    del self._cache[key]  # Remove expired entry
        return None

    def cleanup(self):
        """Remove expired entries from the cache."""
        current_time = time.time()
        with self._lock:
            expired_keys = [key for key, (value, expiration_time) in self._cache.items() if expiration_time <= current_time]
            for key in expired_keys:
                del self._cache[key]

    def __len__(self):
        """Return the number of items in the cache."""
        with self._lock:
            self.cleanup()
            return len(self._cache)

    def clear(self):
        """Clear all items from the cache."""
        with self._lock:
            self._cache.clear()
