import time
from typing import Any, Optional
from threading import Lock
import threading

class CacheEntry:
    def __init__(self, value: Any, ttl: Optional[float] = None):
        self.value = value
        self.created_at = time.time()
        self.expires_at = self.created_at + ttl if ttl is not None else None

    def is_expired(self) -> bool:
        if self.expires_at is None:
            return False
        return time.time() > self.expires_at

class InMemoryCache:
    def __init__(self, default_ttl: Optional[float] = None, cleanup_interval: float = 60.0):
        self._cache = {}
        self._lock = Lock()
        self._default_ttl = default_ttl
        self._cleanup_interval = cleanup_interval
        self._cleanup_timer = None
        self._start_cleanup_timer()

    def get(self, key: str) -> Optional[Any]:
        with self._lock:
            entry = self._cache.get(key)
            if entry is None:
                return None

            if entry.is_expired():
                del self._cache[key]
                return None

            return entry.value

    def set(self, key: str, value: Any, ttl: Optional[float] = None) -> None:
        if ttl is None:
            ttl = self._default_ttl

        with self._lock:
            self._cache[key] = CacheEntry(value, ttl)

    def delete(self, key: str) -> bool:
        with self._lock:
            if key in self._cache:
                del self._cache[key]
                return True
            return False

    def cleanup_expired(self) -> int:
        expired_keys = []

        with self._lock:
            for key, entry in self._cache.items():
                if entry.is_expired():
                    expired_keys.append(key)

            for key in expired_keys:
                del self._cache[key]

        return len(expired_keys)

    def clear(self) -> None:
        with self._lock:
            self._cache.clear()

    def size(self) -> int:
        with self._lock:
            return len(self._cache)

    def _start_cleanup_timer(self) -> None:
        if self._cleanup_interval > 0:
            self._cleanup_timer = threading.Timer(self._cleanup_interval, self._periodic_cleanup)
            self._cleanup_timer.daemon = True
            self._cleanup_timer.start()

    def _periodic_cleanup(self) -> None:
        self.cleanup_expired()
        self._start_cleanup_timer()

    def stop_cleanup(self) -> None:
        if self._cleanup_timer:
            self._cleanup_timer.cancel()
            self._cleanup_timer = None

    def __del__(self):
        self.stop_cleanup()
